1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy] as Cell);
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const liveSet = new Set(liveCells.map(cellKey));
16	  const isLive = (cell: Cell): boolean => liveSet.has(cellKey(cell));
17	
18	  const countLiveNeighbors = (cell: Cell): number =>
19	    neighborsOf(cell).filter(isLive).length;
20	
21	  const candidates = new Map(
22	    liveCells
23	      .flatMap((cell) => [cell, ...neighborsOf(cell)])
24	      .map((cell) => [cellKey(cell), cell] as const),
25	  );
26	
27	  const survives = (cell: Cell): boolean => {
28	    const liveNeighbors = countLiveNeighbors(cell);
29	    const becomesAlive = liveNeighbors === 3;
30	    const staysAlive = liveNeighbors === 2 && isLive(cell);
31	    return becomesAlive || staysAlive;
32	  };
33	
34	  return [...candidates.values()].filter(survives);
35	}
36

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
19	      new Set(block.map((c) => c.join(","))),
20	    );
21	  });
22	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction) — L-shape [(0,0),(1,0),(0,1)] → block [(0,0),(1,0),(0,1),(1,1)]", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
24	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
25	      new Set(["0,0", "1,0", "0,1", "1,1"]),
26	    );
27	  });
28	  it("live cell with more than 3 neighbors dies from overpopulation — filled 3x3 center dies", () => {
29	    const filled: [number, number][] = [
30	      [0, 0], [1, 0], [2, 0],
31	      [0, 1], [1, 1], [2, 1],
32	      [0, 2], [1, 2], [2, 2],
33	    ];
34	    const result = nextGeneration(filled);
35	    const keys = new Set(result.map((c) => c.join(",")));
36	    expect(keys.has("1,1")).toBe(false);
37	  });
38	  it("vertical blinker rotates to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
39	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
40	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
41	      new Set(["-1,1", "0,1", "1,1"]),
42	    );
43	  });
44	  it("horizontal blinker rotates back to vertical — [(-1,1),(0,1),(1,1)] → [(0,0),(0,1),(0,2)]", () => {
45	    const result = nextGeneration([[-1, 1], [0, 1], [1, 1]]);
46	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
47	      new Set(["0,0", "0,1", "0,2"]),
48	    );
49	  });
50	  it.todo("handles negative coordinates correctly");
51	});
